const loadJsPDF = () => new Promise(res => {
  if (window.jspdf) return res(window.jspdf.jsPDF);
  const s = document.createElement("script");
  s.src = "https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js";
  s.onload = () => res(window.jspdf.jsPDF);
  document.head.appendChild(s);
});

function loadHtml2Canvas() {
  return new Promise(res => {
    if (window.html2canvas) return res(window.html2canvas);
    const s = document.createElement("script");
    s.src = "https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js";
    s.onload = () => res(window.html2canvas);
    s.onerror = () => res(null);
    document.head.appendChild(s);
  });
}

function svgToPng(svgEl, width=740, height=330) {
  return new Promise(resolve => {
    try {
      const clone = svgEl.cloneNode(true);
      clone.setAttribute("width", width); clone.setAttribute("height", height);
      const xml = new XMLSerializer().serializeToString(clone);
      const blob = new Blob([xml], {type:"image/svg+xml;charset=utf-8"});
      const url = URL.createObjectURL(blob);
      const img = new Image();
      img.onload = () => {
        const c = document.createElement("canvas");
        c.width = width*2; c.height = height*2;
        const ctx = c.getContext("2d");
        ctx.scale(2,2); ctx.fillStyle="#fff"; ctx.fillRect(0,0,width,height);
        ctx.drawImage(img,0,0,width,height);
        URL.revokeObjectURL(url); resolve(c.toDataURL("image/png"));
      };
      img.onerror = () => { URL.revokeObjectURL(url); resolve(null); };
      img.src = url;
    } catch(e) { resolve(null); }
  });
}

async function buildPDF(sc, notes, disc, sum) {
  const [JsPDF, h2c] = await Promise.all([loadJsPDF(), loadHtml2Canvas()]);
  const doc = new JsPDF({orientation:"portrait", unit:"mm", format:"a4"});
  const PW=210, PH=297, M=14, CW=PW-M*2;
  const g = GENRES.find(g=>g.id===sc.genre);

  // SVG図を取得
  let diagramPng = null;
  const svgNode = document.querySelector(`[data-diagram="${sc.id}"] svg`);
  if (svgNode) diagramPng = await svgToPng(svgNode, 740, 330);

  const esc = s => String(s||"").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/\n/g,"<br/>");

  const SS = (color) => `style="background:${color};color:#fff;font-weight:900;font-size:13px;padding:7px 14px;border-radius:5px;margin:12px 0 7px;"`;
  const FS = `style="background:#f8fafc;border-left:3px solid #cbd5e1;padding:9px 13px;margin-bottom:7px;font-size:11px;line-height:1.85;border-radius:0 5px 5px 0;white-space:pre-wrap;word-break:break-all;"`;
  const LS = `style="font-size:10px;font-weight:700;color:#64748b;margin-bottom:3px;"`;

  const page1 = `<div style="padding:0 16px;font-family:sans-serif;">
    <div style="background:#f97316;color:#fff;padding:14px 18px;margin:0 -16px 16px;font-size:15px;font-weight:900;letter-spacing:1px;">
      🔥 FIRE IMAGE GAME &nbsp;|&nbsp; <span style="font-size:10px;opacity:0.85;font-weight:400;">消防図上訓練レポート　TABLETOP EXERCISE REPORT</span>
    </div>
    <div ${SS('#334155')}>1. 訓練基本情報</div>
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:7px;margin-bottom:7px;">
      <div><div ${LS}>訓練名</div><div ${FS}>${esc(sum.trainName||sc.title)}</div></div>
      <div><div ${LS}>チーム名</div><div ${FS}>${esc(sum.teamName||"未設定")}</div></div>
      <div><div ${LS}>実施日時</div><div ${FS}>${esc(sum.datetime)}</div></div>
      <div><div ${LS}>ジャンル / シナリオ</div><div ${FS}>${esc((g?.icon||"")+" "+(g?.label||"")+"　"+sc.title)}</div></div>
    </div>
    ${diagramPng ? `
    <div ${SS('#f59e0b')}>2. 現場状況図</div>
    <div style="border:1px solid #e2e8f0;border-radius:6px;overflow:hidden;margin-bottom:7px;">
      <img src="${diagramPng}" style="width:100%;display:block;"/>
    </div>` : `<div ${SS('#f59e0b')}>2. 現場状況図</div><div ${FS}>（現場状況図なし）</div>`}
    <div ${SS('#3b82f6')}>3. 状況概要</div>
    <div ${FS}>${esc(sum.situationSummary||sc.situation)}</div>
  </div>`;

  const page2 = `<div style="padding:0 16px;font-family:sans-serif;">
    <div style="background:#f97316;color:#fff;padding:9px 18px;margin:0 -16px 14px;font-size:11px;font-weight:700;">
      🔥 FIRE IMAGE GAME｜訓練レポート（つづき）
    </div>
    <div ${SS('#3b82f6')}>4. 個人考察サマリー</div>
    ${sc.questions.map((q,i)=>`
      <div style="margin-bottom:9px;">
        <div style="display:flex;gap:9px;align-items:flex-start;margin-bottom:4px;">
          <div style="background:#3b82f6;color:#fff;font-weight:900;font-size:10px;padding:3px 9px;border-radius:4px;white-space:nowrap;flex-shrink:0;">Q${i+1}</div>
          <div style="font-size:11px;font-weight:700;color:#1e293b;line-height:1.65;">${esc(q)}</div>
        </div>
        <div ${FS} style="background:#f8fafc;border-left:3px solid #cbd5e1;padding:9px 13px;margin-bottom:7px;font-size:11px;line-height:1.85;border-radius:0 5px 5px 0;white-space:pre-wrap;word-break:break-all;margin-left:32px;">${esc(notes[i]||"（回答なし）")}</div>
      </div>`).join("")}
    <div ${SS('#14b8a6')}>5. 初動判断</div>
    <div ${FS}>${esc(sum.initialDecision)}</div>
    <div ${SS('#14b8a6')}>6. 対応方針・優先順位・戦術</div>
    <div ${FS}>${esc(sum.actionPolicy)}</div>
    <div ${SS('#f97316')}>7. 議論ポイント</div>
    <div ${FS}>${esc(sum.discussionPoints||disc)}</div>
    <div ${SS('#8b5cf6')}>8. 最終結論・統一見解</div>
    <div ${FS}>${esc(sum.finalConclusion)}</div>
    <div style="margin-top:18px;padding-top:10px;border-top:1px solid #e2e8f0;display:flex;justify-content:space-between;font-size:9px;color:#94a3b8;">
      <span>消防図上訓練レポート | ${esc(sum.teamName||"チーム名未設定")} | ${esc(sum.datetime)}</span>
      <span>Fire Image Game</span>
    </div>
  </div>`;

  if (!h2c) {
    // フォールバック（html2canvasなし）
    doc.setFillColor(249,115,22); doc.rect(0,0,PW,18,"F");
    doc.setFontSize(11); doc.setTextColor(255,255,255);
    doc.text("FIRE IMAGE GAME - TABLETOP EXERCISE REPORT", PW/2, 11, {align:"center"});
    let y=26;
    const np=(n)=>{ if(y+n>PH-15){ doc.addPage(); y=22; } };
    const t=(s)=>{ doc.setFontSize(9); doc.setTextColor(40,40,40); const ls=doc.splitTextToSize(String(s||"(none)"),CW); ls.forEach(l=>{ np(5); doc.text(l,M,y); y+=4.5; }); y+=2; };
    t("Team: "+(sum.teamName||"N/A")+"  Date: "+sum.datetime);
    t("Scenario: "+sc.title);
    sc.questions.forEach((q,i)=>{ t("Q"+(i+1)+": "+q); t("A: "+(notes[i]||"(none)")); });
    t("Decision: "+sum.initialDecision);
    t("Policy: "+sum.actionPolicy);
    t("Points: "+(sum.discussionPoints||disc));
    t("Conclusion: "+sum.finalConclusion);
    doc.save("FireImageGame_"+Date.now()+".pdf");
    return;
  }

  const renderHTML = (html) => new Promise(resolve => {
    const div = document.createElement("div");
    div.style.cssText = "position:fixed;top:-9999px;left:-9999px;width:794px;background:#fff;";
    div.innerHTML = html;
    document.body.appendChild(div);
    setTimeout(()=>{
      h2c(div, {scale:2, useCORS:true, allowTaint:true, backgroundColor:"#ffffff", width:794})
        .then(c=>{ document.body.removeChild(div); resolve(c.toDataURL("image/jpeg",0.93)); })
        .catch(()=>{ document.body.removeChild(div); resolve(null); });
    }, 300);
  });

  const img1 = await renderHTML(page1);
  const img2 = await renderHTML(page2);

  if (img1) doc.addImage(img1, "JPEG", 0, 0, PW, PH);
  if (img2) { doc.addPage(); doc.addImage(img2, "JPEG", 0, 0, PW, PH); }

  doc.save("消防図上訓練_"+(sum.teamName||"report")+"_"+Date.now()+".pdf");
}

/* ── COMPONENTS ───────────────────────────────── */
const STEPS = ["シナリオ選択","個人考察","議論ルール","グループ議論","まとめ入力","PDF生成"];

